import * as React from "react";

const initialState = {
  theme: "light",
  setTheme: () => null,
  toggleTheme: () => null,
};

const ThemeProviderContext = React.createContext(initialState);

export function ThemeProvider({
  children,
  defaultTheme = "dark",
  storageKey = "lumenid-theme",
  ...props
}) {
  const [theme, setTheme] = React.useState(() => {
    // Check system preference first, then localStorage, then default
    if (window.matchMedia('(prefers-color-scheme: dark)').matches) {
      return 'dark';
    }
    if (window.matchMedia('(prefers-color-scheme: light)').matches) {
      return 'light';
    }
    try {
      return localStorage.getItem(storageKey) || defaultTheme;
    } catch {
      return defaultTheme;
    }
  });

  // Listen for system theme changes
  React.useEffect(() => {
    const mediaQueryDark = window.matchMedia('(prefers-color-scheme: dark)');
    const mediaQueryLight = window.matchMedia('(prefers-color-scheme: light)');

    const handleSystemChange = () => {
      if (!localStorage.getItem(storageKey)) {
        // Only change if no user preference saved
        setTheme(mediaQueryDark.matches ? 'dark' : 'light');
      }
    };

    mediaQueryDark.addListener(handleSystemChange);
    mediaQueryLight.addListener(handleSystemChange);

    return () => {
      mediaQueryDark.removeListener(handleSystemChange);
      mediaQueryLight.removeListener(handleSystemChange);
    };
  }, [storageKey]);

  React.useEffect(() => {
    const root = window.document.documentElement;
    root.classList.remove("light", "dark");
    root.classList.add(theme);
  }, [theme]);

  const value = {
    theme,
    setTheme: (theme) => {
      try {
        localStorage.setItem(storageKey, theme);
        setTheme(theme);
      } catch {
        setTheme(theme);
      }
    },
    toggleTheme: () => {
      const newTheme = theme === "light" ? "dark" : "light";
      try {
        localStorage.setItem(storageKey, newTheme);
      } catch {
        // Fail silently
      }
      setTheme(newTheme);
    },
  };

  return (
    <ThemeProviderContext.Provider {...props} value={value}>
      {children}
    </ThemeProviderContext.Provider>
  );
}

export const useTheme = () => {
  const context = React.useContext(ThemeProviderContext);
  if (context === undefined)
    throw new Error("useTheme must be used within a ThemeProvider");
  return context;
};

import { useState } from "react";
import { useNavigate } from "react-router";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "../ui/card";
import { Button } from "../ui/button";
import { Badge } from "../ui/badge";
import { Input } from "../ui/input";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "../ui/table";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "../ui/dialog";
import { Textarea } from "../ui/textarea";
import { 
  FileText, 
  Clock, 
  CheckCircle2, 
  XCircle, 
  Search, 
  Eye,
  Download,
  AlertTriangle
} from "lucide-react";
import { toast } from "sonner";

export function VerifierPortal() {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCredential, setSelectedCredential] = useState(null);
  const [reviewDialogOpen, setReviewDialogOpen] = useState(false);
  const [rejectionReason, setRejectionReason] = useState("");
  const [verificationNotes, setVerificationNotes] = useState("");

  const [submissions, setSubmissions] = useState([
    {
      id: "SUB-001",
      customerId: "CUST-123",
      customerName: "Alice Johnson",
      customerEmail: "alice.j@email.com",
      credentialType: "Bachelor's Degree",
      institution: "MIT",
      submittedDate: "2024-02-18",
      status: "pending",
      documents: ["transcript.pdf", "diploma.pdf", "id.pdf"],
      priority: "high"
    },
    {
      id: "SUB-002",
      customerId: "CUST-124",
      customerName: "Bob Smith",
      customerEmail: "bob.smith@email.com",
      credentialType: "Master's Degree",
      institution: "Stanford University",
      submittedDate: "2024-02-17",
      status: "pending",
      documents: ["transcript.pdf", "diploma.pdf"],
      priority: "normal"
    },
    {
      id: "SUB-003",
      customerId: "CUST-125",
      customerName: "Carol Williams",
      customerEmail: "carol.w@email.com",
      credentialType: "Certificate",
      institution: "Harvard Extension",
      submittedDate: "2024-02-16",
      status: "verified",
      documents: ["certificate.pdf"],
      priority: "low"
    }
  ]);

  const filteredSubmissions = submissions.filter(
    (sub) =>
      sub.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      sub.customerEmail.toLowerCase().includes(searchTerm.toLowerCase()) ||
      sub.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
      sub.credentialType.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const pendingSubmissions = submissions.filter(s => s.status === "pending");

  const handleReview = (credential) => {
    setSelectedCredential(credential);
    setReviewDialogOpen(true);
    setRejectionReason("");
    setVerificationNotes("");
  };

  const handleApprove = () => {
    if (selectedCredential) {
      setSubmissions(
        submissions.map((sub) =>
          sub.id === selectedCredential.id ? { ...sub, status: "verified" } : sub
        )
      );
      toast.success(`Credential ${selectedCredential.id} verified`);
      setReviewDialogOpen(false);
      setSelectedCredential(null);
    }
  };

  const handleReject = () => {
    if (selectedCredential && rejectionReason) {
      setSubmissions(
        submissions.map((sub) =>
          sub.id === selectedCredential.id ? { ...sub, status: "rejected" } : sub
        )
      );
      toast.error(`Credential ${selectedCredential.id} rejected`);
      setReviewDialogOpen(false);
      setSelectedCredential(null);
      setRejectionReason("");
    } else {
      toast.error("Please provide a rejection reason");
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case "verified":
        return (
          <Badge className="bg-green-500/20 text-green-400 border-green-500/30">
            <CheckCircle2 className="w-3 h-3 mr-1" />
            Verified
          </Badge>
        );
      case "pending":
        return (
          <Badge className="bg-yellow-500/20 text-yellow-400 border-yellow-500/30">
            <Clock className="w-3 h-3 mr-1" />
            Pending
          </Badge>
        );
      case "rejected":
        return (
          <Badge className="bg-red-500/20 text-red-400 border-red-500/30">
            <XCircle className="w-3 h-3 mr-1" />
            Rejected
          </Badge>
        );
      default:
        return null;
    }
  };

  const getPriorityBadge = (priority) => {
    switch (priority) {
      case "high":
        return <Badge variant="outline" className="bg-red-500/10 text-red-400 border-red-500/30 text-xs">High</Badge>;
      case "normal":
        return <Badge variant="outline" className="bg-blue-500/10 text-blue-400 border-blue-500/30 text-xs">Normal</Badge>;
      case "low":
        return <Badge variant="outline" className="bg-gray-500/10 text-gray-400 border-gray-500/30 text-xs">Low</Badge>;
      default:
        return null;
    }
  };

  return (
    <div className="page-shell">
      <div className="page-container flex flex-col gap-8">
        <div className="flex flex-col gap-2">
          <h1 className="text-5xl font-bold bg-gradient-to-r from-emerald-400 via-teal-400 to-cyan-400 bg-clip-text text-transparent">
            Verification Portal
          </h1>
          <p className="text-lg text-muted-foreground max-w-2xl">
            Review and process incoming credential submissions
          </p>
        </div>

        {pendingSubmissions.some(s => s.priority === "high") && (
          <Card className="border-2 border-red-500/50 bg-red-500/5">
            <CardContent className="py-4">
              <div className="flex items-center gap-3">
                <AlertTriangle className="w-5 h-5 text-red-400" />
                <div>
                  <p className="font-semibold text-red-400">High Priority Items Pending</p>
                  <p className="text-sm text-muted-foreground">
                    {pendingSubmissions.filter(s => s.priority === "high").length} high-priority submissions require immediate attention
                  </p>
                </div>
              </div>
            </CardContent>
          </Card>
        )}

        <Card className="border">
          <CardHeader>
            <div className="flex items-center justify-between">
              <div>
                <CardTitle className="text-xl bg-gradient-to-r from-emerald-500 to-teal-500 bg-clip-text text-transparent">
                  Verification Queue
                </CardTitle>
                <CardDescription>Review and approve credential submissions</CardDescription>
              </div>
              <div className="relative w-64">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input
                  placeholder="Search submissions..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-10"
                />
              </div>
            </div>
          </CardHeader>
          <CardContent>
            <div className="border rounded-lg overflow-hidden">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>ID</TableHead>
                    <TableHead>Customer</TableHead>
                    <TableHead>Type</TableHead>
                    <TableHead>Institution</TableHead>
                    <TableHead>Date</TableHead>
                    <TableHead>Priority</TableHead>
                    <TableHead>Status</TableHead>
                    <TableHead>Actions</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredSubmissions.map((submission) => (
                    <TableRow key={submission.id}>
                      <TableCell className="font-mono text-sm">{submission.id}</TableCell>
                      <TableCell>
                        <div>
                          <p className="font-medium text-sm">{submission.customerName}</p>
                          <p className="text-xs text-muted-foreground">{submission.customerEmail}</p>
                        </div>
                      </TableCell>
                      <TableCell className="text-sm">{submission.credentialType}</TableCell>
                      <TableCell className="text-sm">{submission.institution}</TableCell>
                      <TableCell className="text-sm">{submission.submittedDate}</TableCell>
                      <TableCell>{getPriorityBadge(submission.priority)}</TableCell>
                      <TableCell>{getStatusBadge(submission.status)}</TableCell>
                      <TableCell>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => handleReview(submission)}
                        >
                          <Eye className="w-4 h-4 mr-1" />
                          Review
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          </CardContent>
        </Card>

        <Dialog open={reviewDialogOpen} onOpenChange={setReviewDialogOpen}>
          <DialogContent className="max-w-2xl max-h-[85vh] overflow-y-auto border">
            <DialogHeader>
              <DialogTitle>Review Credential Submission</DialogTitle>
              <DialogDescription>
                Review the details and documents, then approve or reject
              </DialogDescription>
            </DialogHeader>

            {selectedCredential && (
              <div className="space-y-4">
                <Card className="border bg-secondary/50">
                  <CardContent className="pt-4 pb-4">
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <p className="text-xs text-muted-foreground mb-1">Customer</p>
                        <p className="font-semibold text-sm">{selectedCredential.customerName}</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground mb-1">Email</p>
                        <p className="font-semibold text-sm">{selectedCredential.customerEmail}</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground mb-1">Type</p>
                        <p className="font-semibold text-sm">{selectedCredential.credentialType}</p>
                      </div>
                      <div>
                        <p className="text-xs text-muted-foreground mb-1">Institution</p>
                        <p className="font-semibold text-sm">{selectedCredential.institution}</p>
                      </div>
                    </div>
                  </CardContent>
                </Card>

                <div>
                  <h4 className="font-semibold mb-2 text-sm">Submitted Documents</h4>
                  <div className="space-y-2">
                    {selectedCredential.documents.map((doc, index) => (
                      <div
                        key={index}
                        className="flex items-center justify-between p-2 border rounded-lg"
                      >
                        <div className="flex items-center gap-2">
                          <FileText className="w-4 h-4 text-primary" />
                          <span className="text-sm font-medium">{doc}</span>
                        </div>
                        <Button size="sm" variant="ghost">
                          <Download className="w-3 h-3 mr-1" />
                          Download
                        </Button>
                      </div>
                    ))}
                  </div>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-medium">Verification Notes (Optional)</label>
                  <Textarea
                    placeholder="Add internal notes..."
                    value={verificationNotes}
                    onChange={(e) => setVerificationNotes(e.target.value)}
                    rows={2}
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-medium">Rejection Reason (Required if rejecting)</label>
                  <Textarea
                    placeholder="Explain why this credential is being rejected..."
                    value={rejectionReason}
                    onChange={(e) => setRejectionReason(e.target.value)}
                    rows={2}
                  />
                </div>
              </div>
            )}

            <DialogFooter className="gap-2">
              <Button variant="outline" onClick={() => setReviewDialogOpen(false)} size="sm">
                Cancel
              </Button>
              <Button
                variant="destructive"
                onClick={handleReject}
                disabled={!rejectionReason}
                size="sm"
              >
                <XCircle className="w-4 h-4 mr-2" />
                Reject
              </Button>
              <Button
                onClick={handleApprove}
                className="bg-gradient-to-r from-green-500 to-emerald-500 hover:opacity-90 text-white border-0"
                size="sm"
              >
                <CheckCircle2 className="w-4 h-4 mr-2" />
                Approve
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    </div>
  );
}

import React from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { Button } from '../ui/button';
import { Card, CardContent } from '../ui/card';
import {
  Form,
  FormField,
  FormItem,
  FormLabel,
  FormControl,
  FormDescription,
  FormMessage,
} from '../ui/form';
import { EmailInput, PasswordInput, VerificationCodeInput } from './AuthFormFields';
import { useAuthForm } from '../../hooks/useAuthForm';

// Schema
const loginSchema = z.object({
  email: z.string().email('Invalid email').min(1),
  password: z.string().min(8, 'Password must be at least 8 characters'),
}).refine((data) => data.password.length >= 8, {
  message: 'Password too short',
  path: ['password']
});

const verifierSchema = loginSchema.extend({
  verificationCode: z.string().regex(/^\d{6}$/, 'Must be 6 digits')
});

export const LoginForm = ({ role = 'customer', className = '', has2FA = false, headerContent, footerContent }) => {
  const schema = has2FA ? verifierSchema : loginSchema;
  const form = useForm({
    resolver: zodResolver(schema),
    defaultValues: { email: '', password: '', ...(has2FA && { verificationCode: '' }) }
  });
  const { handleSubmit, isLoading } = useAuthForm({ 
    redirect: role === 'verifier' ? '/admin/dashboard' : '/customer/dashboard', 
    role 
  });

  return (
    <Card className={`border border-border/50 bg-card/60 backdrop-blur-xl shadow-xl ${className}`}>
      <CardContent className="pt-6">
        <Form {...form}>
          <form onSubmit={form.handleSubmit(handleSubmit)} className="space-y-6">
            <div className="space-y-4">
              <FormField
                control={form.control}
                name="email"
                render={() => <EmailInput control={form.control} />}
              />
              <FormField
                control={form.control}
                name="password"
                render={() => <PasswordInput control={form.control} />}
              />
              {has2FA && (
                <FormField
                  control={form.control}
                  name="verificationCode"
                  render={() => <VerificationCodeInput control={form.control} />}
                />
              )}
            </div>
            <Button type="submit" className="w-full" disabled={isLoading}>
              {isLoading ? 'Signing in...' : 'Sign In'}
            </Button>
          </form>
        </Form>
        {footerContent}
      </CardContent>
    </Card>
  );
};

import { useState } from "react";
import { useNavigate } from "react-router";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "../ui/card";
import { Button } from "../ui/button";
import { Input } from "../ui/input";
import { Label } from "../ui/label";
import { Textarea } from "../ui/textarea";
import { toast } from "sonner";
import { UserCircle, Mail, Phone, MapPin, GraduationCap, Globe } from "lucide-react";
import { useAuth } from "../../contexts/AuthContext";
import { PageTransition } from "../PageTransition";

export function CustomerProfile() {
  const navigate = useNavigate();
  const { logout } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    fullName: "John Doe",
    email: "john.doe@email.com",
    phone: "+1 (555) 123-4567",
    dateOfBirth: "1995-05-15",
    nationality: "United States",
    address: "123 Main Street",
    city: "San Francisco",
    country: "USA",
    postalCode: "94102",
    institution: "Stanford University",
    degree: "Bachelor of Science",
    fieldOfStudy: "Computer Science",
    graduationDate: "2024-05-20",
    studentId: "STU987654",
    linkedinUrl: "https://linkedin.com/in/johndoe",
    portfolioUrl: "https://johndoe.com",
    bio: "Passionate CS graduate interested in AI and machine learning."
  });

  const handleSave = () => {
    setIsEditing(false);
    toast.success("Profile updated successfully!");
  };

  const handleCancel = () => {
    setIsEditing(false);
    toast.info("Changes cancelled");
  };

  const handleLogout = () => {
    logout();
    toast.success("Logged out successfully");
    navigate("/auth/role-selection");
  };

  return (
    <PageTransition>
      <div className="page-shell">
        <div className="page-container">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
            <div>
              <h1 className="text-5xl font-bold bg-gradient-to-r from-cyan-400 via-blue-400 to-indigo-400 bg-clip-text text-transparent mb-2">
                My Profile
              </h1>
              <p className="text-muted-foreground">Manage your personal information and credentials</p>
            </div>
            <div className="flex items-center gap-3 flex-wrap">
              {!isEditing ? (
                <Button onClick={() => setIsEditing(true)} className="h-10 bg-gradient-to-r from-cyan-500 to-blue-500 text-white border-0">
                  Edit Profile
                </Button>
              ) : (
                <>
                  <Button variant="outline" onClick={handleCancel}>Cancel</Button>
                  <Button onClick={handleSave} className="h-10 bg-gradient-to-r from-cyan-500 to-blue-500 text-white border-0">Save Changes</Button>
                </>
              )}
            </div>
          </div>

          <div className="space-y-6">
            <Card className="border">
              <CardHeader>
                <div className="flex items-center gap-4">
                  <UserCircle className="w-6 h-6 text-primary" />
                  <CardTitle>Personal Information</CardTitle>
                </div>
              </CardHeader>
              <CardContent>
                <div className="grid md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <Label htmlFor="fullName">Full Name</Label>
                    <Input id="fullName" value={formData.fullName} disabled={!isEditing} />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="email">Email</Label>
                    <Input id="email" value={formData.email} disabled={!isEditing} />
                  </div>
                </div>
              </CardContent>
            </Card>
            {/* ... (Address, Education, and Presence cards follow standard JSX input patterns) */}
          </div>
        </div>
      </div>
    </PageTransition>
  );
}

import { useState } from "react";
import { useNavigate } from "react-router";
import { User, GraduationCap, Calendar, Building2, MapPin, FileText, Upload, CheckCircle2, Shield, Copy } from "lucide-react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "../ui/card";
import { Button } from "../ui/button";
import { Input } from "../ui/input";
import { Label } from "../ui/label";
import { Textarea } from "../ui/textarea";
import { toast } from "sonner";
import { PageTransition } from "../PageTransition";

export function ProfileCreation() {
  const navigate = useNavigate();
  const [currentStep, setCurrentStep] = useState(1);
const [secretPhraseConfirmed] = useState(false);
  
  const [secretPhrase] = useState(() => {
    const words = [
      "abandon", "ability", "able", "about", "above", "absent", "absorb", "abstract",
      "absurd", "abuse", "access", "accident", "account", "accuse", "achieve", "acid",
      "acoustic", "acquire", "across", "act", "action", "actor", "actress", "actual",
      "adapt", "add", "addict", "address", "adjust", "admit", "adult", "advance",
      "advice", "aerobic", "affair", "afford", "afraid", "again", "age", "agent",
      "agree", "ahead", "aim", "air", "airport", "aisle", "alarm", "album"
    ];
    const phrase = [];
    for (let i = 0; i < 12; i++) {
      phrase.push(words[Math.floor(Math.random() * words.length)]);
    }
    return phrase;
  });
  
  const [formData, setFormData] = useState({
    dateOfBirth: "",
    nationality: "",
    address: "",
    city: "",
    country: "",
    postalCode: "",
    institution: "",
    degree: "",
    fieldOfStudy: "",
    graduationStatus: "",
    graduationDate: "",
    studentId: "",
    transcriptFile: null,
    diplomaFile: null,
    idDocumentFile: null,
    linkedinUrl: "",
    portfolioUrl: "",
    bio: ""
  });

  const steps = [
    { number: 1, title: "Personal Information", icon: User },
    { number: 2, title: "Education Details", icon: GraduationCap },
    { number: 3, title: "Document Upload", icon: Upload },
    { number: 4, title: "Additional Info", icon: FileText },
    { number: 5, title: "Secret Phrase", icon: Shield }
  ];

  const handleFileChange = (e, field) => {
    if (e.target.files && e.target.files[0]) {
      setFormData({ ...formData, [field]: e.target.files[0] });
    }
  };

  const handleNext = () => {
    if (currentStep < 4) {
      setCurrentStep(currentStep + 1);
    }
  };

  const handlePrevious = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const handleSubmit = () => {
    setCurrentStep(5);
  };

  const handleCopySecretPhrase = () => {
    navigator.clipboard.writeText(secretPhrase.join(" "));
    setSecretPhraseCopied(true);
    toast.success("Secret phrase copied to clipboard!");
  };

  const handleConfirmAndFinish = () => {
    if (!secretPhraseConfirmed) {
      toast.error("Please confirm that you have saved your secret phrase");
      return;
    }
    toast.success("Profile created successfully! Redirecting to dashboard...");
    setTimeout(() => {
      navigate("/customer/dashboard");
    }, 1500);
  };

  return (
    <PageTransition>
      <div className="min-h-screen py-grid-12 px-grid-4 sm:px-grid-6 lg:px-grid-8">
        <div className="max-w-4xl mx-auto flex flex-col gap-8">
          <div className="text-center mt-8 flex flex-col items-center gap-4">
            <h1 className="text-5xl font-bold bg-gradient-to-r from-cyan-400 via-blue-400 to-indigo-400 bg-clip-text text-transparent">
              Create Your Profile
            </h1>
            <p className="text-muted-foreground text-lg">
              Complete your profile to start managing your credentials
            </p>
          </div>

          <div className="flex items-center justify-between max-w-3xl mx-auto w-full">
            {steps.map((step, index) => {
              const Icon = step.icon;
              const isActive = currentStep === step.number;
              const isCompleted = currentStep > step.number;
              
              return (
                <div key={step.number} className="flex items-center flex-1">
                  <div className="flex flex-col items-center flex-1 gap-2">
                    <div
                      className={`w-14 h-14 rounded-full flex items-center justify-center transition-all duration-300 ${
                        isCompleted
                          ? "bg-gradient-to-br from-cyan-500 to-blue-500 shadow-lg shadow-cyan-500/30"
                          : isActive
                          ? "bg-gradient-to-br from-cyan-500 to-blue-500 shadow-lg shadow-cyan-500/30 scale-110"
                          : "bg-secondary/50 border-2 border-border/50 backdrop-blur-xl"
                      }`}
                    >
                      {isCompleted ? (
                        <CheckCircle2 className="w-6 h-6 text-white" />
                      ) : (
                        <Icon className={`w-6 h-6 ${isActive ? "text-white" : "text-muted-foreground"}`} />
                      )}
                    </div>
                    <p className={`text-xs text-center max-w-[80px] leading-tight ${isActive ? "font-semibold text-cyan-400" : "text-muted-foreground"}`}>
                      {step.title}
                    </p>
                  </div>
                  {index < steps.length - 1 && (
                    <div className={`h-0.5 flex-1 mx-3 transition-all duration-300 ${isCompleted ? "bg-gradient-to-r from-cyan-500 to-blue-500" : "bg-border/50"}`} />
                  )}
                </div>
              );
            })}
          </div>

          <Card className="border border-border/50 bg-card/60 backdrop-blur-xl shadow-lg">
            <CardHeader className="border-b border-border/50 bg-card/40 backdrop-blur-xl">
              <CardTitle className="text-2xl bg-gradient-to-r from-cyan-400 via-blue-400 to-indigo-400 bg-clip-text text-transparent">
                Step {currentStep}: {steps[currentStep - 1].title}
              </CardTitle>
              <CardDescription className="text-base">
                {currentStep === 1 && "Tell us about yourself"}
                {currentStep === 2 && "Share your educational background"}
                {currentStep === 3 && "Upload your credential documents"}
                {currentStep === 4 && "Add optional information to enhance your profile"}
                {currentStep === 5 && "Secure your profile with a secret phrase"}
              </CardDescription>
            </CardHeader>
            <CardContent className="p-grid-6">
              <form style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-section-small)' }}>
                {currentStep === 1 && (
                  <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-component-medium)' }}>
                    <div className="grid md:grid-cols-2 gap-grid-4">
                      <div className="space-y-2">
                        <Label htmlFor="dateOfBirth" className="flex items-center gap-2">
                          <Calendar className="w-4 h-4" />
                          Date of Birth
                        </Label>
                        <Input
                          id="dateOfBirth"
                          type="date"
                          value={formData.dateOfBirth}
                          onChange={(e) => setFormData({ ...formData, dateOfBirth: e.target.value })}
                          required
                          className="bg-background/50 border-border/50"
                        />
                      </div>
                      <div className="space-y-2">
                        <Label htmlFor="nationality">Nationality</Label>
                        <Input
                          id="nationality"
                          placeholder="e.g., United States"
                          value={formData.nationality}
                          onChange={(e) => setFormData({ ...formData, nationality: e.target.value })}
                          required
                          className="bg-background/50 border-border/50"
                        />
                      </div>
                    </div>
                    {/* ... (Address fields follow same pattern) */}
                  </div>
                )}
                {/* Steps 2-5 continue using standard JSX patterns without type annotations */}
                
                <div className="flex gap-grid-3 pt-grid-6 border-t border-border/50">
                  {currentStep > 1 && currentStep !== 5 && (
                    <Button
                      type="button"
                      onClick={handlePrevious}
                      variant="outline"
                      className="flex-1 h-12 border-border/50 bg-background/50 backdrop-blur-xl hover:bg-secondary/50"
                    >
                      Previous
                    </Button>
                  )}
                  {currentStep < 4 ? (
                    <Button
                      type="button"
                      onClick={handleNext}
                      className="flex-1 h-12 bg-gradient-to-r from-cyan-500 via-blue-500 to-indigo-500 hover:opacity-90 text-white border-0 shadow-lg shadow-cyan-500/30"
                    >
                      Next Step
                    </Button>
                  ) : currentStep === 4 ? (
                    <Button
                      type="button"
                      onClick={handleSubmit}
                      className="flex-1 h-12 bg-gradient-to-r from-green-500 to-emerald-500 hover:opacity-90 text-white border-0 shadow-lg shadow-green-500/30"
                    >
                      <CheckCircle2 className="w-4 h-4 mr-2" />
                      Complete Profile
                    </Button>
                  ) : (
                    <Button
                      type="button"
                      onClick={handleConfirmAndFinish}
                      className="flex-1 h-12 bg-gradient-to-r from-green-500 to-emerald-500 hover:opacity-90 text-white border-0 shadow-lg shadow-green-500/30"
                      disabled={!secretPhraseConfirmed}
                    >
                      <Shield className="w-4 h-4 mr-2" />
                      Confirm & Finish
                    </Button>
                  )}
                </div>
              </form>
            </CardContent>
          </Card>
        </div>
      </div>
    </PageTransition>
  );
}

